import React from "react";
import IconButton from "@material-ui/core/IconButton";
import Tooltip from "@material-ui/core/Tooltip";
import CompareArrowsIcon from "@material-ui/icons/CompareArrows";
import EditIcon from '@material-ui/icons/Edit';
import DeleteIcon from '@material-ui/icons/Delete';
import PersonAddDisabledIcon from '@material-ui/icons/PersonAddDisabled';
import IndeterminateCheckBoxIcon from "@material-ui/icons/IndeterminateCheckBox";
import { withStyles } from "@material-ui/core/styles";
import states from "../api/states";
import yearsofex from "../api/yearsofex";
import { editTimetable, deleteTimetable, findFormStreams, findTeachers, findSubjects, } from "../api/api";
import PageSpinner from 'components/PageSpinner';
import {
  Button,
  ButtonGroup,
  FormGroup,
  Form,
  Label,
  Input,
  Card,
  CardBody,
  CardHeader,
  Col,
  Modal,
  ModalBody,
  ModalFooter,
  ModalHeader,
  Row,
  Alert,
} from 'reactstrap';

const defaultToolbarSelectStyles = {
  iconButton: {
  },
  iconContainer: {
    marginRight: "24px",
  },
  inverseIcon: {
    transform: "rotate(90deg)",
  },
};

class CustomToolbarSelectTimetable extends React.Component {
  constructor(props)
  {
    super(props);
    this.state = {
        showEditModal:false,
        saved:false,
        id: '',
        day : 'nn',
        date : '',
        time:'',
        stream : 'nn',
        teacher : 'nn',
        subject : 'nn',
        xtoken:'',
        preload:false,
        streams:[],
        teachers:[],
        subjects:[],
        msg: '',
        error: '',
    };
  }
  hideEditModal = () => {
    this.setState({
      ...this.state,
      showEditModal:false,
    });
    if(this.state.saved)
    {
      this.props.rerenderParentCallback();
    }
  }
    handleDayInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, day: v,});
    }
    handleDateInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, date: v,});
    }
    handleTimeInput = (event) => {
      const v = event.target.value;
      this.setState({...this.state, time: v,});
    }
    handleStreamInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, stream: v,});
    }
    handleSubjectInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, subject: v,});
    }
    handleTeacherInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, teacher: v,});
    }
  handleEditSaveChanges = () => {
      // console.log('id is', this.state);
      this.setState({
        ...this.state,
        preload:true,
      });
      editTimetable(this.state.xtoken, this.state, this.state.id)
      .then((response) => {
        // console.log('id is', response);
          if( response.status === 200)
          {
            this.setState({
              ...this.state,
              saved:true,
              error: '',
              msg: response.message,
              preload:false,
            });
          }
          else
          {
              this.setState({
                  ...this.state,
                  error: response.message,
                  msg: '',
                  preload:false,
              });
          }
      })
      .catch((error) => {
          this.setState({
              ...this.state,
              error: 'Connection error occured',
              preload:false,
          });
          console.log('error', error);
      });
  }
  handleClickEditRow = () => {
    let dataIndex = this.props.selectedRows.data[0]['dataIndex'];
    let selectedRowData = this.props.originalData[dataIndex];
    findFormStreams(this.props.Xtoken).then((response) => {
        this.setState({
            showEditModal:true,
            id: selectedRowData.id,
            day : selectedRowData.day,
            date : selectedRowData.date,
            time:selectedRowData.time,
            stream : selectedRowData.stream,
            teacher : selectedRowData.teacher,
            subject : selectedRowData.subject,
            xtoken:this.props.Xtoken,
            streams:response.data,
        });
    }).catch((respError) => {});
    findTeachers(this.props.Xtoken).then((response) => {
        this.setState({
            ...this.state,
            teachers:response.data,
        });
    }).catch((respError) => {});
    findSubjects(this.props.Xtoken).then((response) => {
        this.setState({
            ...this.state,
            subjects:response.data,
        });
    }).catch((respError) => {});
  }
  handleDeleteSelection = () => {
    let dataIndex = this.props.selectedRows.data[0]['dataIndex'];
    let selectedRowData = this.props.originalData[dataIndex];
    deleteTimetable(this.props.Xtoken, selectedRowData.id)
    .then((response) => {
      if(response.status === 200 )
      {
        alert(response.message);
        this.props.rerenderParentCallback();
        return;
      }
      alert(response.message);
      return;
    })
    .catch((error) => {
      alert('Connection error occured');
    });
  };

  handleClickDeselectAll = () => {
    this.props.setSelectedRows([]);
  };

  handleClickBlockSelected = () => {
    console.log(`block users with dataIndexes: ${this.props.selectedRows.data.map(row => row.dataIndex)}`);
  };

  render() {
    const { classes } = this.props;

    return (
      <div className={classes.iconContainer}>
        <Tooltip title={"Edit row"}>
          <IconButton className={classes.iconButton} onClick={this.handleClickEditRow}>
            <EditIcon className={classes.icon} />
          </IconButton>
        </Tooltip>
        <Tooltip title={"Deselect row"}>
          <IconButton className={classes.iconButton} onClick={this.handleClickDeselectAll}>
            <IndeterminateCheckBoxIcon className={classes.icon} />
          </IconButton>
        </Tooltip>
        <Tooltip title={"Delete row"}>
          <IconButton className={classes.iconButton} onClick={this.handleDeleteSelection}>
            <DeleteIcon className={classes.icon} />
          </IconButton>
        </Tooltip>
        {/* modals */}
        <Modal
          size="lg"
          isOpen={this.state.showEditModal}
          backdrop={false}>
          <ModalHeader>
            Edit Lesson
            {this.state.preload && (<PageSpinner/>)}
            {this.state.error.length > 0 && (
              <div>
                <br></br><Alert color="danger">{this.state.error}</Alert>
              </div>
            )}
            {this.state.msg.length > 0 && (
              <div>
                <br></br><Alert color="success">{this.state.msg}</Alert>
              </div>
            )}
          </ModalHeader>
          <ModalBody>
            <Row>
                <Col xl={4} lg={12} md={12}>
                <Card>
                    <CardBody>
                    <Form>
                        <FormGroup>
                        <Label for="exampleSelect">Week Day *</Label>
                        <Input onChange={this.handleDayInput} value={this.state.day} defaultValue={this.state.day} type="select" name="frm">
                            <option value="nn" disabled={true}>Select day</option>
                            <option value={'Monday'}>{'Monday'}</option>
                            <option value={'Tuesday'}>{'Tuesday'}</option>
                            <option value={'Wednesday'}>{'Wednesday'}</option>
                            <option value={'Thursday'}>{'Thursday'}</option>
                            <option value={'Friday'}>{'Friday'}</option>
                            <option value={'Saturday'}>{'Saturday'}</option>
                        </Input>
                        </FormGroup>
                        <FormGroup>
                        <Label for="exampleEmail">Date*</Label>
                        <Input onChange={this.handleDateInput}
                            type="date" 
                            value={this.state.date}
                            name="frm"
                            placeholder=""
                        />
                        </FormGroup>
                    </Form>
                    </CardBody>
                </Card>
                </Col>
                <Col xl={4} lg={12} md={12}>
                <Card>
                    <CardBody>
                    <Form>
                    <FormGroup>
                        <Label for="exampleEmail">Time*</Label>
                        <Input onChange={this.handleTimeInput}
                            type="time" 
                            value={this.state.time}
                            name="frm"
                            placeholder=""
                        />
                        </FormGroup>
                        <FormGroup>
                        <Label for="exampleSelect">Stream *</Label>
                        <Input onChange={this.handleStreamInput} value={this.state.stream} defaultValue={this.state.stream} type="select" name="frm">
                            <option value="nn" disabled={true}>Select stream</option>
                            {this.state.streams.map((stt, idx) => (
                                <option value={stt.id}>{stt.form + stt.name}</option>
                            ))}
                        </Input>
                        </FormGroup>
                    </Form>
                    </CardBody>
                </Card>
                </Col>
                <Col xl={4} lg={12} md={12}>
                <Card>
                    <CardBody>
                    <Form>
                    <FormGroup>
                        <Label for="exampleSelect">Subject *</Label>
                        <Input onChange={this.handleSubjectInput} value={this.state.subject} defaultValue={this.state.subject} type="select" name="frm">
                            <option value="nn" disabled={true}>Select subject</option>
                            {this.state.subjects.map((stt, idx) => (
                                <option value={stt.id}>{stt.label}</option>
                            ))}
                        </Input>
                        </FormGroup>
                        <FormGroup>
                        <Label for="exampleSelect">Teacher *</Label>
                        <Input onChange={this.handleTeacherInput} value={this.state.teacher} defaultValue={this.state.teacher} type="select" name="frm">
                            <option value="nn" disabled={true}>Select teacher</option>
                            {this.state.teachers.map((stt, idx) => (
                                <option value={stt.id}>{stt.fname + ' ' + stt.lname}</option>
                            ))}
                        </Input>
                        </FormGroup>
                    </Form>
                    </CardBody>
                </Card>
                </Col>              
            </Row>
          </ModalBody>
          <ModalFooter>
            <Button color="primary" onClick={this.handleEditSaveChanges}>
              Save changes
            </Button>{' '}
            <Button color="secondary" onClick={this.hideEditModal}>
              Close
            </Button>
          </ModalFooter>
        </Modal>
      </div>
    );
  }
}

export default withStyles(defaultToolbarSelectStyles, { name: "CustomToolbarSelectTimetable" })(CustomToolbarSelectTimetable);