import Page from 'components/Page';
import React from 'react';
import {
  Button,
  Card,
  CardBody,
  CardHeader,
  Col,
  Form,
  FormFeedback,
  FormGroup,
  FormText,
  Input,
  Label,
  Row,
  Alert,
  Table,
} from 'reactstrap';
import states from "../api/states";
import yearsofex from "../api/yearsofex";
import { newTimetable, findTimetables, findFormStreams, findTeachers, findSubjects } from "../api/api";
import AsyncStorage from '@callstack/async-storage';
import conf from "../api/config";
import PageSpinner from 'components/PageSpinner';
import MUIDataTable from "mui-datatables";
import CustomToolbarSelectTimetable from "../components/CustomToolbarSelectTimetable";
class TimetablesPage extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
          day : 'nn',
          date : '',
          time:'',
          stream : 'nn',
          teacher : 'nn',
          subject : 'nn',
          xtoken:'',
          msg: '',
          error: '',
          preload:false,
          downloadFile:true,
          data: [],
          streams:[],
          teachers:[],
          subjects:[],
        };
        AsyncStorage.getItem(conf.secret)
        .then((results) => {
          if( results !== null )
          {
            let obje_results = JSON.parse(results);
            this.setState({
              ...this.state,
              xtoken : obje_results.user.token,
            });
            findTimetables(obje_results.user.token).then((response) => {
                console.log('data-data', response.data);
                this.setState({
                    ...this.state,
                    data:response.data,
                });
            }).catch((respError) => {});
            findFormStreams(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    streams:response.data,
                });
            }).catch((respError) => {});
            findTeachers(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    teachers:response.data,
                });
            }).catch((respError) => {});
            findSubjects(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    subjects:response.data,
                });
            }).catch((respError) => {});
          }
        })
        .catch((error) => {
          console.log('storage error', error);
        });
    }
    componentDidMount() {
    }

    rerenderParentCallback = () => {
      findTimetables (this.state.xtoken).then((response) => {
        this.setState({
            ...this.state,
            data:response.data,
        });
      }).catch((respError) => {
      });
    }
    
    handleDayInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, day: v,});
    }
    handleDateInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, date: v,});
    }
    handleTimeInput = (event) => {
      const v = event.target.value;
      this.setState({...this.state, time: v,});
    }
    handleStreamInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, stream: v,});
    }
    handleSubjectInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, subject: v,});
    }
    handleTeacherInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, teacher: v,});
    }
    handleSaveChanges = () => {
        // console.log('so far', this.state);
        this.setState({
          ...this.state,
          preload:true,
        });
        newTimetable(this.state.xtoken, this.state)
        .then((response) => {
            // console.log('so_far', response);
            if( response.status === 200)
            {
                this.setState({
                    ...this.state,
                    stream : 'nn',
                    subject : 'nn',
                    teacher:'nn',
                    msg: response.message,
                    data: response.data,
                    error: '',
                    preload:false,
                });

                this.forceUpdate();
            }
            else
            {
                this.setState({
                    ...this.state,
                    error: response.message,
                    msg: '',
                    preload:false,
                });
            }
        })
        .catch((error) => {
            this.setState({
                ...this.state,
                error: 'Connection error occured',
                preload:false,
            });
            console.log('error', error);
        });
    }
    render() {
        const columns = [
            {
              name: 'Id',
              options: {
                display: false
              }
            },
            'Day',
            'Time',
            'Class',
            'Subject',
            'Teacher',
        ];

        const data2 = () => {
          let rtn = [];
          this.state.data.map(item => {
            rtn.push([
                item.id,
                item.day,
                item.time,
                item.slabel,
                item.sublabel,
                item.tlabel,
            ]);
          });
          return rtn;
        }
      
        const options = {
            filter: true,
            selectableRows: 'single',
            selectableRowsOnClick:true,
            filterType: 'dropdown',
            responsive: 'vertical',
            draggableColumns: {
              enabled: true
            },
            rowsPerPage: 5,
            selectToolbarPlacement: 'replace',
            customToolbarSelect: (selectedRows, displayData, setSelectedRows) => (
              <CustomToolbarSelectTimetable rerenderParentCallback={this.rerenderParentCallback} selectedRows={selectedRows} displayData={displayData} setSelectedRows={setSelectedRows}  originalData={this.state.data} Xtoken={this.state.xtoken}/>
            ),
            downloadOptions: {
                filename: 'school-data-excel-format.csv',
                separator: ';',
                filterOptions: {
                  useDisplayedColumnsOnly: true,
                  useDisplayedRowsOnly: true,
                }
            },
            onDownload: (buildHead, buildBody, columns, data2) => {
              if (this.state.downloadFile) {
                let val= `${buildHead(columns)}${buildBody(data2)}`.trim();
                return val;
              }
      
              return false;
            },
            onRowSelectionChange: (currentRowsSelected, allRows, rowsSelected) => {
              // console.log('currentRowsSelected', currentRowsSelected);
            },
            onRowsDelete: rowsDeleted => {
              // console.log(rowsDeleted, 'were deleted!');
            },
            onChangePage: numberRows => {
              // console.log(numberRows);
            },
            onSearchChange: searchText => {
              // console.log(searchText);
            },
            onColumnSortChange: (column, direction) => {
              // console.log(column, direction);
            },
            onViewColumnsChange: (column, action) => {
              // console.log(column, action);
            },
            onFilterChange: (column, filters) => {
              // console.log(column, filters);
            },
            onCellClick: (cellIndex, rowIndex) => {
              // console.log(cellIndex, rowIndex);
            },
            onRowClick: (rowData, rowState) => {
              // console.log(rowData, rowState);
            },
        };
      return (
        <Page title="Academics - Timetable" breadcrumbs={[{ name: 'Timetable', active: true }]}>
          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardHeader>Create Lesson {this.state.preload && (<PageSpinner/>)} </CardHeader>
                {this.state.error.length > 0 && (
                    <Alert color="danger">{this.state.error}</Alert>
                )}
                {this.state.msg.length > 0 && (
                    <Alert color="success">{this.state.msg}</Alert>
                )}
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                <Form>
                    <FormGroup>
                      <Label for="exampleSelect">Week Day *</Label>
                      <Input onChange={this.handleDayInput} value={this.state.day} defaultValue={this.state.day} type="select" name="frm">
                        <option value="nn" disabled={true}>Select day</option>
                        <option value={'Monday'}>{'Monday'}</option>
                        <option value={'Tuesday'}>{'Tuesday'}</option>
                        <option value={'Wednesday'}>{'Wednesday'}</option>
                        <option value={'Thursday'}>{'Thursday'}</option>
                        <option value={'Friday'}>{'Friday'}</option>
                        <option value={'Saturday'}>{'Saturday'}</option>
                      </Input>
                    </FormGroup>
                    <FormGroup>
                      <Label for="exampleEmail">Date*</Label>
                      <Input onChange={this.handleDateInput}
                        type="date" 
                        value={this.state.date}
                        name="frm"
                        placeholder=""
                      />
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                  <FormGroup>
                      <Label for="exampleEmail">Time(24-hour format)*</Label>
                      <Input onChange={this.handleTimeInput}
                        type="time" 
                        value={this.state.time}
                        name="frm"
                        placeholder=""
                      />
                    </FormGroup>
                    <FormGroup>
                      <Label for="exampleSelect">Stream *</Label>
                      <Input onChange={this.handleStreamInput} value={this.state.stream} defaultValue={this.state.stream} type="select" name="frm">
                        <option value="nn" disabled={true}>Select stream</option>
                        {this.state.streams.map((stt, idx) => (
                            <option value={stt.id}>{stt.form + stt.name}</option>
                        ))}
                      </Input>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                  <FormGroup>
                      <Label for="exampleSelect">Subject *</Label>
                      <Input onChange={this.handleSubjectInput} value={this.state.subject} defaultValue={this.state.subject} type="select" name="frm">
                        <option value="nn" disabled={true}>Select subject</option>
                        {this.state.subjects.map((stt, idx) => (
                            <option value={stt.id}>{stt.label}</option>
                        ))}
                      </Input>
                    </FormGroup>
                    <FormGroup>
                      <Label for="exampleSelect">Teacher *</Label>
                      <Input onChange={this.handleTeacherInput} value={this.state.teacher} defaultValue={this.state.teacher} type="select" name="frm">
                        <option value="nn" disabled={true}>Select teacher</option>
                        {this.state.teachers.map((stt, idx) => (
                            <option value={stt.id}>{stt.fname + ' ' + stt.lname}</option>
                        ))}
                      </Input>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>              
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                    <FormGroup check row>
                      <Col sm={{ size: 10, offset: 2 }}>
                        <Button type="button" onClick={this.handleSaveChanges}>Add lesson</Button>
                      </Col>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardBody>
                    <MUIDataTable title={'List of lessons'}
                    data={this.state.data.map(item => {
                      return [
                        item.id,
                        item.day,
                        item.time,
                        item.slabel,
                        item.sublabel,
                        item.tlabel,
                      ]
                    })} columns={columns} options={options} />
                </CardBody>
              </Card>
            </Col>
          </Row>
    
        </Page>
      );
    }
}
export default TimetablesPage;
